INSERT INTO publications (publication_id, title, bio, cover_image_url) VALUES
(14, 'অনন্যা', 'সৃজনশীল সাহিত্য, উপন্যাস এবং বিভিন্ন জনপ্রিয় লেখকের সমগ্র ও সংকলন প্রকাশের জন্য সুপরিচিত প্রকাশনী।', ''),
(15, 'আফসার ব্রাদার্স', 'শিশু-কিশোর সাহিত্য, সায়েন্স ফিকশন এবং সমকালীন কথাসাহিত্য প্রকাশের জন্য একটি সুপরিচিত প্রকাশনা সংস্থা।', ''),
(16, 'পত্রভারতী', 'কলকাতাভিত্তিক একটি শীর্ষস্থানীয় প্রকাশনা সংস্থা, যা মানসম্পন্ন কিশোর সাহিত্য ও বিভিন্ন থ্রিলার উপন্যাসের জন্য সুপরিচিত।', ''),
(17, 'অন্যধারা', 'বাংলাদেশের সৃজনশীল গ্রন্থ, গল্প, উপন্যাস এবং সমকালীন মননশীল সাহিত্য প্রকাশের কাজে যুক্ত প্রকাশনী।', ''),
(18, 'অনুপম প্রকাশনী', 'বিজ্ঞানমনস্ক ও গবেষণামূলক প্রবন্ধ, অনুবাদ এবং ধ্রুপদী সাহিত্য প্রকাশের জন্য একটি বিশ্বস্ত প্রকাশনা সংস্থা।', ''),
(19, 'পেন্সিল পাবলিকেশনস', 'নতুন ও সম্ভাবনাময় লেখকদের সমকালীন সাহিত্য, কবিতা ও ব্যতিক্রমী ঘরানার বই প্রকাশের জন্য পরিচিত।', ''),
(20, 'জ্ঞানকোষ প্রকাশনী', 'তথ্যমূলক গ্রন্থ, সাধারণ জ্ঞান, অনুবাদ সাহিত্য এবং সৃজনশীল ফিকশন প্রকাশের জন্য সুপরিচিত প্রকাশনা সংস্থা।', '');